def merge_within(pairs):
    sorted_pairs = sorted(pairs)
    merged_pairs = [sorted_pairs[0]]

    for pair in sorted_pairs[1:]:
        last_merged = merged_pairs[-1]
        if pair[0] <= last_merged[1]:
            merged_pairs[-1][1] = max(last_merged[1], pair[1])
        else:
            merged_pairs.append(pair)

    return merged_pairs
